nta.declaration:
// =====================================================================
//  TOTAL BANDWIDTH SERVER -- CONTINUOUS, VERIFIABLE MODEL
// =====================================================================
//  This is a non-terminating variant of the TBS model. Unlike the
//  bounded [0,HORIZON) version, here:
//    * periodic tasks are released forever (every T_i),
//    * aperiodic requests arrive forever as a SPORADIC stream
//      (nondeterministic interarrival in [MIT, MITMAX]),
//    * the Scheduler never stops -- there is no Done location.
//
//  KEY IDEA -- RELATIVE TIME.
//  There is no ever-growing "currentTime". Instead every temporal
//  quantity is a bounded countdown that is decremented by one each
//  tick (advanceTime). EDF only needs the ORDER of deadlines, and the
//  TBS rule only needs differences, so relative counters suffice. This
//  keeps the state space FINITE, so A[] queries still terminate even
//  though the system runs for unbounded time.
//
//  RATE-LIMIT ASSUMPTION.
//  A continuously schedulable system requires the aperiodic load to
//  stay within the reserved bandwidth: minimum interarrival
//      MIT >= C_k / U_s = C_k * serverBandwidthDen / serverBandwidthNum.
//  Otherwise the TBS deadline max(r_k,d_{k-1})+C_k/U_s is pushed to
//  infinity (unbounded backlog). This bound is what both (a) makes the
//  system schedulable and (b) keeps serverSlack -- and the whole model
//  -- bounded.
//
//  Whole set schedulable  iff   U_p + U_s <= 1.
// =====================================================================

// ---------- helper constants ----------
const int NO_JOB       = -1;     // CPU idle / nothing selected
const int INF_DEADLINE = 1000;   // larger than any bounded relative deadline

// =====================================================================
//  1) PERIODIC TASK SET (hard real-time, scheduled by EDF)
// =====================================================================
const int N_PERIODIC = 2;                            // number of periodic tasks

//                                       tau0 tau1
const int periodicPeriod   [N_PERIODIC] = { 4,  6 };  // T_i
const int periodicWCET     [N_PERIODIC] = { 1,  2 };  // C_i
const int periodicDeadline [N_PERIODIC] = { 4,  6 };  // D_i (= T_i, implicit)

// runtime state, all RELATIVE and bounded
int[0,8] periodicTimeToRelease [N_PERIODIC];  // ticks until next release (0 -> release now)
int[0,8] periodicRelDeadline   [N_PERIODIC];  // ticks until current job's deadline
int[0,4] periodicRemaining     [N_PERIODIC];  // remaining execution time
bool     periodicActive        [N_PERIODIC];  // is a job ready?

// =====================================================================
//  2) APERIODIC WORKLOAD (soft, served by the Total Bandwidth Server)
//     A single sporadic generator feeds a small pool of job slots.
// =====================================================================
const int MAX_APERIODIC  = 4;    // pool size (bounded number of outstanding jobs)
const int APERIODIC_WCET = 2;    // C_k of each aperiodic job (worst case)
const int MIT    = 8;            // min interarrival = C_k/U_s -> load <= U_s
const int MITMAX = 16;           // max interarrival (lighter load)

int[0,16] aperiodicRelDeadline [MAX_APERIODIC];  // TBS deadline, relative
int[0,4]  aperiodicRemaining   [MAX_APERIODIC];  // remaining execution time
bool      aperiodicActive      [MAX_APERIODIC];  // slot in use?
bool      aperiodicOverflow = false;             // set if the pool ever overflows

// =====================================================================
//  3) TOTAL BANDWIDTH SERVER parameters
//     U_s = serverBandwidthNum / serverBandwidthDen = 1/4
// =====================================================================
const int serverBandwidthNum = 1;
const int serverBandwidthDen = 4;

// d_{k-1} expressed RELATIVE to now (floored at 0). This is the running
// server deadline used by the TBS rule; it is bounded by C_k/U_s.
int[0,16] serverSlack    = 0;
int[0,16] aperiodicTimer = 2;    // ticks until next aperiodic arrival

// =====================================================================
//  4) GLOBAL SCHEDULER STATE + synchronisation
// =====================================================================
int[NO_JOB, N_PERIODIC+MAX_APERIODIC] runningJob = NO_JOB;
bool deadlineMiss = false;

broadcast chan release;          // scheduler -> generators: "release jobs due now"

typedef int[0, N_PERIODIC-1] periodic_id_t;

// ---------- small helper ----------
int imax(int a, int b) { return a > b ? a : b; }

// ---------------------------------------------------------------------
//  GENERATOR ACTIONS
// ---------------------------------------------------------------------

// release a fresh job of periodic task "id" and re-arm its period timer
void releasePeriodicJob(periodic_id_t id) {
    periodicRemaining[id]     = periodicWCET[id];
    periodicRelDeadline[id]   = periodicDeadline[id];
    periodicActive[id]        = true;
    periodicTimeToRelease[id] = periodicPeriod[id];   // next release in T_i ticks
}

// first free slot in the aperiodic pool, or NO_JOB if full
int allocAperiodicSlot() {
    int s;
    for (s = 0; s < MAX_APERIODIC; s++)
        if (!aperiodicActive[s]) return s;
    return NO_JOB;
}

// inject one aperiodic request and assign its TBS deadline:
//   d_k = max(r_k, d_{k-1}) + C_k / U_s
// in relative form: serverSlack := max(0, serverSlack) + C_k*den/num
void injectAperiodic() {
    int s;
    s = allocAperiodicSlot();
    if (s == NO_JOB) { aperiodicOverflow = true; return; }
    serverSlack =
        imax(0, serverSlack)
        + (APERIODIC_WCET * serverBandwidthDen) / serverBandwidthNum;
    aperiodicRelDeadline[s] = serverSlack;
    aperiodicRemaining[s]   = APERIODIC_WCET;
    aperiodicActive[s]      = true;
}

// ---------------------------------------------------------------------
//  SCHEDULER ACTIONS
// ---------------------------------------------------------------------

// a job misses if it is still unfinished when its relative deadline hits 0
void checkDeadlineMisses() {
    int i;
    int k;
    for (i = 0; i < N_PERIODIC; i++)
        if (periodicActive[i] && periodicRemaining[i] > 0 &&
            periodicRelDeadline[i] <= 0)
            deadlineMiss = true;
    for (k = 0; k < MAX_APERIODIC; k++)
        if (aperiodicActive[k] && aperiodicRemaining[k] > 0 &&
            aperiodicRelDeadline[k] <= 0)
            deadlineMiss = true;
}

// EDF over all ready jobs (smallest relative deadline). Ties go to the
// server (aperiodic), consistent with the bounded model.
//   periodic  job id = i                (0 .. N_PERIODIC-1)
//   aperiodic job id = N_PERIODIC + k    (k = 0 .. MAX_APERIODIC-1)
int selectEarliestDeadlineJob() {
    int i;
    int k;
    int best         = NO_JOB;
    int bestDeadline = INF_DEADLINE;
    for (i = 0; i < N_PERIODIC; i++)
        if (periodicActive[i] && periodicRemaining[i] > 0 &&
            periodicRelDeadline[i] < bestDeadline) {
            bestDeadline = periodicRelDeadline[i];
            best         = i;
        }
    for (k = 0; k < MAX_APERIODIC; k++)
        if (aperiodicActive[k] && aperiodicRemaining[k] > 0 &&
            aperiodicRelDeadline[k] <= bestDeadline) {   // "<=" -> server wins ties
            bestDeadline = aperiodicRelDeadline[k];
            best         = N_PERIODIC + k;
        }
    return best;
}

// give the running job one unit of CPU
void executeOneTimeUnit() {
    int k;
    if (runningJob != NO_JOB) {
        if (runningJob < N_PERIODIC) {
            periodicRemaining[runningJob]--;
            if (periodicRemaining[runningJob] == 0)
                periodicActive[runningJob] = false;
        } else {
            k = runningJob - N_PERIODIC;
            aperiodicRemaining[k]--;
            if (aperiodicRemaining[k] == 0)
                aperiodicActive[k] = false;
        }
    }
}

// advance time by one tick: decrement every relative counter (floored at 0).
// This replaces "currentTime++" of the bounded model.
void advanceTime() {
    int i;
    int k;
    for (i = 0; i < N_PERIODIC; i++) {
        if (periodicTimeToRelease[i] > 0) periodicTimeToRelease[i]--;
        if (periodicActive[i] && periodicRelDeadline[i] > 0) periodicRelDeadline[i]--;
    }
    for (k = 0; k < MAX_APERIODIC; k++)
        if (aperiodicActive[k] && aperiodicRelDeadline[k] > 0) aperiodicRelDeadline[k]--;
    if (serverSlack    > 0) serverSlack--;
    if (aperiodicTimer > 0) aperiodicTimer--;
}

template.declaration:
// Sporadic source: whenever its interarrival timer reaches 0 it injects
// a new aperiodic request, assigns the TBS deadline, and re-arms the
// timer to a NONDETERMINISTIC value in [MIT, MITMAX]. Runs forever.

nta.system:
// Automatic instantiation:
//   - one PeriodicGenerator per value of periodic_id_t  (N_PERIODIC procs)
//   - one sporadic AperiodicGenerator
//   - one Scheduler (the CPU)
system PeriodicGenerator, AperiodicGenerator, Scheduler;
